// ML Detector for signal detection
// r = received signal vector
// constellation = set of M possible transmitted signals

FUNCTION MLDetector(r, constellation):
 minDistance = ∞
 detectedIndex = -1

 FOR i FROM 0 TO constellation.length-1:
 d = euclideanDistance(r, constellation[i])
 IF d < minDistance:
 minDistance = d
 detectedIndex = i

 RETURN detectedIndex

