// Binary to Gray code conversion
FUNCTION binaryToGray(binary):
 gray = binary
 shiftRight = binary >> 1
 gray = gray XOR shiftRight
 RETURN gray

// Generate Gray-coded constellation indices
FUNCTION generateGrayIndices(M):
 indices = []
 FOR i FROM 0 TO M-1:
 indices.append(binaryToGray(i))
 RETURN indices

// For M=4 (QPSK): indices = [0, 1, 3, 2]
// Binary: 00, 01, 10, 11
// Gray: 00, 01, 11, 10 (adjacent differ by 1 bit)
